const { event, data } = context;
const cfg = cliaas.config;
if (event === 'ticket.created' && !cfg.notifyOnCreate) return;
if (event === 'ticket.resolved' && !cfg.notifyOnResolve) return;
if (event === 'sla.breached' && !cfg.notifyOnBreach) return;
const channel = cfg.channel || '#general';
cliaas.log.info(`Would post to ${channel}: [${event}] ${data.subject || data.ticketId}`);
